// ============================================================
// SEED FUNCTION
// ============================================================
async function seedTable(table: string, data: Record<string, unknown>[]) {
  // Clear existing data, then insert fresh
  const { error: deleteError } = await supabase.from(table).delete().gte("created_at", "1970-01-01")
  if (deleteError) {
    console.error(`  ⚠️  Could not clear ${table}: ${deleteError.message} — inserting anyway`)
  }
  const { error, count } = await supabase.from(table).insert(data, { count: "exact" })
  if (error) {
    console.error(`  ❌ ${table} error: ${error.message}`)
    return false
  }
  console.log(`  ✅ ${table}: ${count ?? data.length} records`)
  return true
}

async function seed() {
  console.log("🍄 Starting Supabase seed...\n")

  const allSpecies = [...species, ...speciesBatch2]

  console.log(`📋 Species Library (${allSpecies.length})...`)
  await seedTable("species_library", allSpecies)

  console.log(`📋 Contamination Library (${contamination.length})...`)
  await seedTable("contamination_library", contamination)

  console.log(`📋 SOP Templates (${sops.length})...`)
  await seedTable("sop_templates", sops)

  console.log(`📋 Knowledge Base (${knowledgeBase.length})...`)
  await seedTable("knowledge_base", knowledgeBase)

  const total = allSpecies.length + contamination.length + sops.length + knowledgeBase.length
  console.log(`\n🎉 Seed complete! ${total} total records across 4 tables.`)
}

seed().catch(console.error)
